esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS
    commit_rate = SUM(RATE(ibmmq_qmgr_commit_total)),
    rollback_rate = SUM(RATE(ibmmq_qmgr_rollback_total))
    BY attributes.qmgr
// Require a minimum commit rate to avoid false positives on idle queue managers
| WHERE commit_rate IS NOT NULL AND commit_rate > 0
    AND rollback_rate IS NOT NULL
| EVAL rollback_pct = ROUND(rollback_rate / (commit_rate + rollback_rate) * 100.0, 2)
// Alert when rollback rate exceeds 5% of total transactions
// < 1% is healthy; 1-5% is warning; > 5% is critical
// High rollback ratios indicate poison messages, processing failures,
// or resource contention causing transaction failures
// Adjust threshold and minimum commit rate for your workload
| WHERE rollback_pct > 5.0
